SELECT year, month, dayofmonth, flight_date, day_of_week_name, is_weekend, airport, airport_city, airport_state, direction, COUNT(*) AS total_flights, SUM(CASE WHEN cancelled = 0 AND diverted = 0 THEN 1 ELSE 0 END) AS operated_flights, SUM(CASE WHEN cancelled = 1 THEN 1 ELSE 0 END) AS cancelled_flights, ROUND(100.0 * SUM(CASE WHEN delay <= 15 AND cancelled = 0 AND diverted = 0 THEN 1 ELSE 0 END) / NULLIF(SUM(CASE WHEN cancelled = 0 AND diverted = 0 THEN 1 ELSE 0 END), 0), 2) AS on_time_pct, ROUND(AVG(CASE WHEN cancelled = 0 THEN delay END), 2) AS avg_delay_min, ROUND(AVG(CASE WHEN cancelled = 0 THEN taxi END), 2) AS avg_taxi_min, COUNT(DISTINCT reporting_airline) AS num_carriers, COUNT(DISTINCT peer_airport) AS num_connected_airports FROM (SELECT CAST(year AS INT) AS year, CAST(month AS INT) AS month, CAST(dayofmonth AS INT) AS dayofmonth, flightdate AS flight_date, CASE CAST(dayofweek AS INT) WHEN 1 THEN 'Monday' WHEN 2 THEN 'Tuesday' WHEN 3 THEN 'Wednesday' WHEN 4 THEN 'Thursday' WHEN 5 THEN 'Friday' WHEN 6 THEN 'Saturday' WHEN 7 THEN 'Sunday' ELSE 'Unknown' END AS day_of_week_name, CASE WHEN CAST(dayofweek AS INT) IN (6, 7) THEN 'Weekend' ELSE 'Weekday' END AS is_weekend, origin AS airport, COALESCE(origincityname, origin) AS airport_city, COALESCE(originstatename, '') AS airport_state, dest AS peer_airport, 'Departure' AS direction, depdelay AS delay, taxiout AS taxi, cancelled, diverted, reporting_airline FROM silver_flights UNION ALL SELECT CAST(year AS INT), CAST(month AS INT), CAST(dayofmonth AS INT), flightdate, CASE CAST(dayofweek AS INT) WHEN 1 THEN 'Monday' WHEN 2 THEN 'Tuesday' WHEN 3 THEN 'Wednesday' WHEN 4 THEN 'Thursday' WHEN 5 THEN 'Friday' WHEN 6 THEN 'Saturday' WHEN 7 THEN 'Sunday' END, CASE WHEN CAST(dayofweek AS INT) IN (6, 7) THEN 'Weekend' ELSE 'Weekday' END, dest, COALESCE(destcityname, dest), COALESCE(deststatename, ''), origin, 'Arrival', arrdelay, taxiin, cancelled, diverted, reporting_airline FROM silver_flights) GROUP BY year, month, dayofmonth, flight_date, day_of_week_name, is_weekend, airport, airport_city, airport_state, direction
